ldName": "observer.name", "meta": {"type": "string"}, "label": "Device", "customLabel": true}, {"columnId": "bh_y", "fieldName": "satisfaction", "meta": {"type": "number"}, "label": "Satisfaction %", "customLabel": true}], "timeField": "@timestamp"}}, "indexPatternRefs": [{"id": "metrics-unifi.device-default-d49df5be5e334a31edfeddf37e20da6ec02aa388ec7a1e2718411a2964efb9df", "title": "metrics-unifi.device-default", "timeField": "@timestamp"}]}}, "internalReferences": [{"type": "index-pattern", "id": "metrics-unifi.device-default-d49df5be5e334a31edfeddf37e20da6ec02aa388ec7a1e2718411a2964efb9df", "name": "indexpattern-datasource-layer-bh_layer"}], "visualization": {"preferredSeriesType": "bar_horizontal", "legend": {"isVisible": false, "shouldTruncate": false, "position": "right", "legendSize": "auto"}, "layers": [{"layerId": "bh_layer", "accessors": ["bh_y"], "layerType": "data", "seriesType": "bar_horizontal", "xAccessor": "bh_x"}]}, "adHocDataViews": {"metrics-unifi.device-default-d49df5be5e334a31edfeddf37e20da6ec02aa388ec7a1e2718411a2964efb9df": {"id": "metrics-unifi.device-default-d49df5be5e334a31edfeddf37e20da6ec02aa388ec7a1e2718411a2964efb9df", "title": "metrics-unifi.device-default", "name": "metrics-unifi.device-default", "sourceFilters": [], "fieldFormats": {}, "runtimeFieldMap": {}, "fieldAttrs": {}, "allowNoIndex": false, "allowHidden": false, "type": "esql"}}, "query": {"esql": "FROM metrics-unifi.device-default | WHERE metrics.unifi.device.satisfaction > 0 | STATS satisfaction = MAX(metrics.unifi.device.satisfaction) BY observer.name | SORT satisfaction ASC | LIMIT 10"}, "filters": []}, "references": [], "version": 2}}, "panelIndex": "device-satisfaction", "gridData": {"y": 42, "x": 32, "w": 16, "h": 10, "i": "device-satisfaction"}}, {"type": "visualization", "embeddableConfig": {"savedVis": {"id": "", "title": "UniFi Network Topology", "description": "", "type": "vega", "params": {"spec": "{
  "$schema": "https://vega.github.io/schema/vega/v5.json",
  "padding": {
    "top": 10,
    "left": 10,
    "right": 10,
    "bottom": 10
  },
  "background": "#16161f",
  "data": [
    {
      "name": "device_metrics",
      "url": {
        "%type%": "esql",
        "query": "FROM metrics-unifi.device-default | WHERE @timestamp > NOW() - 10 MINUTES | STATS state = MAX(`metrics.unifi.device.state`), satisfaction = MAX(`metrics.unifi.device.satisfaction`), num_clients = MAX(`metrics.unifi.device.num_clients`) BY device_name = `observer.name`"
      }
    },
    {
      "name": "nodes",
      "values": [
        {
          "id": "udm-pro",
          "label": "UDM-Pro",
          "mac": "74:ac:b9:d9:f1:d5",
          "role": "Gateway",
          "col": 0,
          "row": 1
        },
        {
          "id": "usw-pro-24",
          "label": "USW Pro 24 PoE",
          "mac": "74:ac:b9:a7:d1:76",
          "role": "Core Switch",
          "col": 1,
          "row": 1
        },
        {
          "id": "basement-ap",
          "label": "Basement AP",
          "mac": "d8:b3:70:5f:6d:6e",
          "role": "Access Point",
          "col": 2,
          "row": 0
        },
        {
          "id": "garage-ap",
          "label": "Garage AP",
          "mac": "d8:b3:70:51:7d:c7",
          "role": "Access Point",
          "col": 2,
          "row": 1
        },
        {
          "id": "usw-flex-mini",
          "label": "USW Flex Mini",
          "mac": "74:ac:b9:d3:36:c9",
          "role": "Switch",
          "col": 2,
          "row": 2
        }
      ],
      "transform": [
        {
          "type": "formula",
          "as": "x",
          "expr": "datum.col == 0 ? width * 0.09 : datum.col == 1 ? width * 0.27 : width * 0.53"
        },
        {
          "type": "formula",
          "as": "y",
          "expr": "datum.col == 2 ? (datum.row == 0 ? 150 : datum.row == 1 ? 360 : 510) : 300"
        },
        {
          "type": "lookup",
          "from": "device_metrics",
          "key": "device_name",
          "fields": [
            "label"
          ],
          "values": [
            "state",
            "satisfaction",
            "num_clients"
          ],
          "as": [
            "state",
            "satisfaction",
            "num_clients"
          ],
          "default": null
        },
        {
          "type": "formula",
          "as": "status_color",
          "expr": "datum.state === 1 ? '#00e676' : datum.state === 0 ? '#ef5350' : '#ffc107'"
        },
        {
          "type": "formula",
          "as": "border_color",
          "expr": "datum.state === 1 ? '#2a6640' : datum.state === 0 ? '#663030' : '#665030'"
        },
        {
          "type": "formula",
          "as": "card_fill",
          "expr": "datum.state === 1 ? '#1c3028' : datum.state === 0 ? '#301c1c' : '#302818'"
        },
        {
          "type": "formula",
          "as": "status_text",
          "expr": "datum.state === 1 ? 'ONLINE' : datum.state === 0 ? 'OFFLINE' : 'NO DATA'"
        },
        {
          "type": "formula",
          "as": "sat_label",
          "expr": "isValid(datum.satisfaction) && datum.satisfaction > 0 ? 'Sat: ' + datum.satisfaction + '%' : 'Sat: --'"
        },
        {
          "type": "formula",
          "as": "clients_label",
          "expr": "isValid(datum.num_clients) && datum.num_clients > 0 ? datum.num_clients + ' clients' : ''"
        },
        {
          "type": "formula",
          "as": "rx",
          "expr": "datum.x - 85"
        },
        {
          "type": "formula",
          "as": "ry",
          "expr": "datum.y - 48"
        },
        {
          "type": "formula",
          "as": "dot_x",
          "expr": "datum.x - 71"
        },
        {
          "type": "formula",
          "as": "dot_y",
          "expr": "datum.y - 32"
        },
        {
          "type": "formula",
          "as": "st_x",
          "expr": "datum.x - 58"
        },
        {
          "type": "formula",
          "as": "st_y",
          "expr": "datum.y - 28"
        },
        {
          "type": "formula",
          "as": "lbl_y",
          "expr": "datum.y - 6"
        },
        {
          "type": "formula",
          "as": "rl_y",
          "expr": "datum.y + 10"
        },
        {
          "type": "formula",
          "as": "div_y",
          "expr": "datum.y + 21"
        },
        {
          "type": "formula",
          "as": "bot_y",
          "expr": "datum.y + 36"
        },
        {
          "type": "formula",
          "as": "div_x1",
          "expr": "datum.x - 75"
        },
        {
          "type": "formula",
          "as": "div_x2",
          "expr": "datum.x + 75"
        },
        {
          "type": "formula",
          "as": "cl_x",
          "expr": "datum.x + 73"
        }
      ]
    },
    {
      "name": "edges",
      "values": [
        {
          "source": "udm-pro",
          "target": "usw-pro-24"
        },
        {
          "source": "usw-pro-24",
          "target": "basement-ap"
        },
        {
          "source": "usw-pro-24",
          "target": "garage-ap"
        },
        {
          "source": "usw-pro-24",
          "target": "usw-flex-mini"
        }
      ],
      "transform": [
        {
          "type": "lookup",
          "from": "nodes",
          "key": "id",
          "fields": [
            "source"
          ],
          "values": [
            "x",
            "y",
            "state"
          ],
          "as": [
            "sx",
            "sy",
            "s_state"
          ]
        },
        {
          "type": "lookup",
          "from": "nodes",
          "key": "id",
          "fields": [
            "target"
          ],
          "values": [
            "x",
            "y",
            "state"
          ],
          "as": [
            "tx",
            "ty",
            "t_state"
          ]
        },
        {
          "type": "formula",
          "as": "edge_color",
          "expr": "datum.s_state === 1 && datum.t_state === 1 ? '#2a7a50' : '#7a3030'"
        }
      ]
    },
    {
      "name": "client_metrics",
      "url": {
        "%type%": "esql",
        "query": "FROM metrics-unifi.client-default | WHERE @timestamp > NOW() - 5 MINUTES AND `metrics.unifi.client.is_wired` == false AND `metrics.unifi.client.wifi.ap_mac` IS NOT NULL | STATS hostname = MAX(`client.hostname`), ip = MAX(TO_STRING(`client.ip`)), ap_mac = MAX(`metrics.unifi.client.wifi.ap_mac`), signal_dbm = MAX(`metrics.unifi.client.wifi.signal_dbm`) BY mac = `client.mac` | SORT hostname ASC | LIMIT 40"
      }
    },
    {
      "name": "client_counts",
      "source": "client_metrics",
      "transform": [
        {
          "type": "aggregate",
          "groupby": [
            "ap_mac"
          ],
          "ops": [
            "count"
          ],
          "fields": [
            null
          ],
          "as": [
            "group_count"
          ]
        }
      ]
    },
    {
      "name": "clients",
      "source": "client_metrics",
      "transform": [
        {
          "type": "lookup",
          "from": "nodes",
          "key": "mac",
          "fields": [
            "ap_mac"
          ],
          "values": [
            "x",
            "y"
          ],
          "as": [
            "parent_x",
            "parent_y"
          ]
        },
        {
          "type": "window",
          "sort": {
            "field": "hostname"
          },
          "groupby": [
            "ap_mac"
          ],
          "ops": [
            "row_number"
          ],
          "as": [
            "rank"
          ]
        },
        {
          "type": "lookup",
          "from": "client_counts",
          "key": "ap_mac",
          "fields": [
            "ap_mac"
          ],
          "values": [
            "group_count"
          ],
          "as": [
            "group_count"
          ]
        },
        {
          "type": "filter",
          "expr": "datum.rank < 5"
        },
        {
